def write_text(rel_path: str, content: str) -> None:
    path = ROOT / rel_path
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content.rstrip() + "\n", encoding="utf-8")


def render_doc(doc: dict, title_map: dict[str, str]) -> str:
    review = doc.get("review", "Annual")
    section_label = {
        "Policy": "Policy Requirements",
        "Procedure": "Procedure Requirements",
        "Standard": "Control Requirements",
        "Template": "Instructions for Use",
        "Guide": "Guidance",
        "Methodology": "Methodology Requirements",
        "Governance": "Governance Requirements",
    }.get(doc["type"], "Requirements")
    role_lines = [
        "- The CTO is the document approver and provides executive authorization for this document.",
        "- The Head of IT is the document owner and is responsible for implementation, maintenance, and periodic review.",
    ]
    if doc["type"] in {"Policy", "Standard", "Methodology", "Governance"}:
        role_lines += [
            "- Managers shall ensure that personnel within their areas of responsibility comply with the requirements of this document.",
            "- All workers, contractors, and third parties in scope shall comply with the requirements defined in this document.",
        ]
    else:
        role_lines += [
            "- Process participants shall perform the activities defined in this document and retain evidence where required.",
            "- System owners and control owners shall support execution of this document within their assigned environments.",
        ]
    review_text = {
        "Annual": "at least annually",
        "Quarterly": "at least quarterly",
        "Monthly": "at least monthly",
        "Semi-annual": "at least semi-annually",
        "Annual and upon significant change": "at least annually and upon significant change",
        "Per event": "for each relevant event and formally reviewed annually",
    }.get(review, f"at least {review.lower()}")
    all_sections = list(doc["sections"]) + SUPPLEMENTS.get(doc["id"], [])
    lines = [
        f"# {doc['title']}",
        "",
        "| Document Control | Value |",
        "| --- | --- |",
        f"| Document ID | {doc['id']} |",
        f"| Document Type | {doc['type']} |",
        "| Classification | Internal Use |",
        f"| Owner | {OWNER} |",
        f"| Approver | {APPROVER} |",
        f"| Review Frequency | {review} |",
        "| Version | 1.0 |",
        f"| Effective Date | {TODAY} |",
        "",
        "## 1. Purpose",
        doc["purpose"],
        "",
        "## 2. Scope",
        doc["scope"],
        "",
        "## 3. Authority and Compliance",
        f"This {doc['type'].lower()} is issued under the authority of the {APPROVER}. Compliance with this document is mandatory for all personnel, contractors, and third parties within its scope. Non-compliance shall be addressed through management action, corrective action, contractual enforcement, or disciplinary measures as applicable.",
        "",
        "## 4. Roles and Responsibilities",
        *role_lines,
        "",
        f"## 5. {section_label}",
    ]
    for index, (header, items) in enumerate(all_sections, start=1):
        lines.append(f"### 5.{index} {header}")
        for item in items:
            lines.append(f"- {item}")
        lines.append("")
    if doc.get("related"):
        lines.append("## 6. Related Documents")
        for rid in doc["related"]:
            lines.append(f"- {rid} - {title_map.get(rid, rid)}")
        lines.append("")
    lines += [
        "## 7. Exceptions and Deviations",
        "Any exception, deviation, or temporary waiver from this document shall be documented, risk-assessed, approved by the Head of IT, and authorized by the CTO before implementation unless emergency conditions prevent prior approval.",
        "",
        "## 8. Review and Maintenance",
        f"This document shall be reviewed {review_text} and whenever significant changes occur to the business, technology stack, supplier model, organizational structure, or applicable legal and contractual obligations.",
    ]
    return "\n".join(lines)


def col_name(n: int) -> str:
    s = ""
    while n:
        n, r = divmod(n - 1, 26)
        s = chr(65 + r) + s
    return s


def sheet_xml(rows: list[list[str]]) -> str:
    widths: dict[int, int] = {}
    for row in rows:
        for i, v in enumerate(row, start=1):
            widths[i] = max(widths.get(i, 12), min(max(len(str(v)) + 2, 12), 60))
    cols = "".join(
        f'<col min="{i}" max="{i}" width="{widths[i]}" customWidth="1"/>'
        for i in range(1, max(widths) + 1)
    ) if widths else ""
    xml_rows = []
    for r_idx, row in enumerate(rows, start=1):
        cells = []
        for c_idx, value in enumerate(row, start=1):
            ref = f"{col_name(c_idx)}{r_idx}"
            style = "1" if r_idx == 1 else "0"
            txt = escape(str(value))
            cells.append(
                f'<c r="{ref}" s="{style}" t="inlineStr"><is><t xml:space="preserve">{txt}</t></is></c>'
            )
        xml_rows.append(f'<row r="{r_idx}">' + "".join(cells) + "</row>")
    return (
        '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
        '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" '
        'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
        '<sheetViews><sheetView workbookViewId="0"><pane ySplit="1" topLeftCell="A2" '
        'activePane="bottomLeft" state="frozen"/><selection pane="bottomLeft"/>'
        "</sheetView></sheetViews><sheetFormatPr defaultRowHeight=\"15\"/>"
        + (f"<cols>{cols}</cols>" if cols else "")
        + f"<sheetData>{''.join(xml_rows)}</sheetData></worksheet>"
    )


