docs.extend([
    {"id":"README","type":"Guide","path":"README.md","title":"ISMS Package Overview","purpose":"Provide a navigation guide for the ISO 27001:2022 document package created for a remote-first software company operating company-owned equipment in a colocated datacenter and Azure.","scope":"This guide covers the full document set, workbooks, templates, and assumptions prepared in this package.","sections":[("Package Contents",["01_Governance contains ISMS governance documents, the Statement of Applicability, and the annual review schedule.","02_Policies contains the formal policy suite used to address applicable Annex A controls.","03_Procedures_and_Standards contains operating procedures and technical standards referenced by the policies.","04_Registers_and_Templates contains practical templates for evidence generation and recurring review activities.","ISO27001_2022_Control_Mapping.xlsx provides the Annex A control mapping, implementation status, document mapping, and document register in Excel format.","ISO27001_2022_Review_Schedule.xlsx provides the annual review schedule and recurring review checklist in Excel format."]),("Assumptions",["The organization is a fully remote software company with approximately 300 workers in scope.","The organization uses Microsoft 365, Azure, GitLab, Jira, Confluence, CrowdStrike, Intune, Fortigate, and Entra SSO with MFA.","Company laptops are managed through Intune and protected by CrowdStrike. Mobile devices are BYOD and restricted through app protection policies.","A small office is used for shipments only, with no production equipment hosted there. Printing is prohibited.","Company-owned infrastructure is installed in a third-party colocation facility. Physical visits are limited to authorized personnel.","No customer personal information is handled. Employee and business information remain in scope."]),("Use Guidance",["Replace assumptions that require organization-specific wording before formal adoption.","Run the annual schedule and retain the generated evidence in a controlled repository.","Keep the Statement of Applicability aligned with the risk assessment, supplier inventory, and current architecture."])],"related":["GOV-01","GOV-02","GOV-03","GOV-04"]},
    {"id":"GOV-01","type":"Policy","path":"01_Governance/GOV-01-Information-Security-Governance-Policy.md","title":"Information Security Governance Policy","purpose":"Define the governance framework for the ISMS, including policy approval, security objectives, roles, oversight, compliance monitoring, and management review.","scope":"Applies to all workers, information assets, SaaS platforms, Azure resources, GitLab repositories, collaboration tools, company-managed endpoints, and company-owned systems hosted in the colocation facility.","sections":[("Governance Requirements",["The CTO shall approve the ISMS scope, policy suite, security objectives, risk treatment decisions, and annual management review outputs.","The Head of IT shall operate the ISMS, maintain the risk register, coordinate evidence collection, and report control status to management.","Security responsibilities shall be assigned in job descriptions, procedures, and system ownership records.","Conflicting duties shall be segregated for code deployment, infrastructure administration, financial approval, and access approval where practical.","Management shall ensure workers understand and follow security obligations relevant to their roles."]),("External Coordination",["The organization shall maintain contact points for law enforcement, regulators when applicable, incident response support, cyber insurance, and relevant security communities.","Threat intelligence from vendors, CERTs, mailing lists, and trusted advisories shall be reviewed and incorporated into defensive actions."]),("Assurance Activities",["The ISMS shall be independently reviewed through internal audit or equivalent independent assessment at least annually.","Compliance with policies, procedures, and standards shall be monitored through audits, reviews, sampling, and corrective actions.","Documented operating procedures shall exist for recurring operational tasks that affect security, resilience, or evidence generation."])],"related":["GOV-02","GOV-03","GOV-04","POL-08","POL-09"]},
    {"id":"GOV-02","type":"Methodology","path":"01_Governance/GOV-02-Risk-Assessment-and-Treatment-Methodology.md","title":"Risk Assessment and Treatment Methodology","purpose":"Define how information security risks are identified, analyzed, evaluated, treated, accepted, and monitored within the ISMS.","scope":"Applies to strategic, operational, supplier, physical, personnel, and technical risks affecting the scoped environment.","sections":[("Method",["Risks shall be identified for assets, business processes, suppliers, facilities, software development, remote working, and technology services.","Likelihood and impact shall each be rated on a five-point scale. Overall risk shall be determined by multiplying likelihood and impact.","Impact evaluation shall consider confidentiality, integrity, availability, legal obligations, financial loss, and operational disruption."]),("Treatment Options",["Risks may be treated by implementing or strengthening controls, transferring risk through contractual or insurance means, avoiding the activity, or formally accepting the residual risk.","Residual risk acceptance requires documented rationale, owner acknowledgement, and approval by the CTO.","Annex A controls shall be considered during treatment planning, and the Statement of Applicability shall be updated when applicability changes."]),("Review Triggers",["The risk register shall be reviewed at least quarterly and whenever a major technology, supplier, office, datacenter, or product change occurs.","Post-incident lessons learned, audit findings, test failures, and significant exceptions shall feed risk updates."])],"related":["GOV-03","TMP-03","POL-09","POL-10","POL-11"]},
    {"id":"POL-01","type":"Policy","path":"02_Policies/POL-01-Asset-Acceptable-Use-and-Information-Handling-Policy.md","title":"Asset, Acceptable Use and Information Handling Policy","purpose":"Control the identification, ownership, use, classification, labeling, transfer, retention, deletion, and return of information and associated assets.","scope":"Applies to information assets in Microsoft 365, Azure, GitLab, Jira, Confluence, laptops, removable media, shipment processes, and paper records where permitted.","sections":[("Asset and Ownership Requirements",["Information and technology assets shall be inventoried, assigned an owner, and reviewed at least annually.","Owners shall define acceptable use, handling requirements, retention expectations, and recovery requirements for assets within their responsibility."]),("Acceptable Use and Handling",["Workers shall use company assets only for authorized business purposes and shall not disable approved security controls.","Printing company information is prohibited unless explicitly approved by the Head of IT for a time-bound business need.","Information shall be classified at least as Public, Internal, Confidential, or Restricted and handled according to the classification scheme.","Labels or equivalent metadata shall be applied to documents, repositories, systems, or workspaces containing Confidential or Restricted information.","Transfers of sensitive information shall use approved encrypted channels and company-managed services."]),("Media, Retention and Disposal",["Use of removable media is prohibited by default and requires documented business approval.","Business records shall be retained, protected from unauthorized change, and disposed of securely when no longer needed.","Information deletion shall be performed using vendor-supported purge features or sanitization methods appropriate to the medium.","Company assets shall be returned or securely destroyed when no longer required or upon termination."])],"related":["PR-10","POL-07","POL-11"]},
    {"id":"POL-02","type":"Policy","path":"02_Policies/POL-02-Access-Control-and-Identity-Management-Policy.md","title":"Access Control and Identity Management Policy","purpose":"Define how identities are created, authenticated, authorized, reviewed, and removed across the scoped environment.","scope":"Applies to Entra SSO, Microsoft 365, Azure, GitLab, Jira, Confluence, Fortigate VPN, privileged accounts, source code, and administrative tooling.","sections":[("Identity and Authentication Requirements",["All workforce identities shall be unique, centrally managed where possible, and linked to a documented business need.","MFA shall be enforced for Microsoft 365, Azure, GitLab, Atlassian services, Fortigate VPN, and all privileged administration.","Authentication secrets shall be protected, rotated when compromise is suspected, and never shared through unsecured channels."]),("Access Authorization",["Access shall follow least privilege and role-based assignment where practical.","Privileged access shall be limited to named administrators, approved by management, and periodically reviewed.","Source code write access, production deployment rights, and security tooling administration shall be restricted and monitored."]),("Lifecycle and Review",["Joiner, mover, leaver actions shall be completed through a documented workflow with manager approval.","User access shall be reviewed at least quarterly and privileged access at least quarterly.","Access to utility programs, shells, and direct production administration shall be restricted to authorized administrators only.","Installation of software on production systems and company endpoints shall be limited to approved mechanisms and authorized personnel."])],"related":["PR-01","PR-03","PR-09"]},
    {"id":"POL-03","type":"Policy","path":"02_Policies/POL-03-Human-Resources-and-Remote-Working-Security-Policy.md","title":"Human Resources and Remote Working Security Policy","purpose":"Define personnel security, onboarding, training, confidentiality, disciplinary expectations, event reporting, and remote working requirements.","scope":"Applies to employees, contractors, interns, temporary workers, and other users granted access to company information or systems.","sections":[("Personnel Security",["Screening shall be performed before granting access in accordance with legal requirements and role sensitivity.","Employment agreements and contractor terms shall define security responsibilities, confidentiality obligations, acceptable use, and return of assets.","All personnel shall complete security awareness training at onboarding and at least annually thereafter."]),("Remote Working",["Remote work shall be performed only on company-managed laptops or approved virtual environments.","Home workspaces shall protect screens from casual observation, use full-disk encryption, and lock automatically when unattended.","BYOD mobile access shall be restricted to approved mobile applications protected by app protection policies and conditional access.","Workers shall report suspected security events immediately through the documented incident reporting channels."]),("Employment Change and Exit",["Managers and IT shall coordinate role changes, access updates, and terminations on or before the effective date.","Disciplinary action may be taken for intentional or negligent violations of security policy.","Confidentiality obligations shall survive termination where contractually required."])],"related":["PR-01","PR-03","POL-10"]},
    {"id":"POL-04","type":"Policy","path":"02_Policies/POL-04-Physical-and-Environmental-Security-Policy.md","title":"Physical and Environmental Security Policy","purpose":"Protect company assets hosted in the colocation facility, shipment office, and remote environments from unauthorized physical access, theft, damage, and environmental threats.","scope":"Applies to the shipping office, remote working locations, company laptops, portable assets, storage media, and company-owned infrastructure installed at the colocation facility.","sections":[("Facility Security",["Physical security perimeters and entry controls shall protect company-controlled spaces and assets.","The shipping office shall remain locked when unattended and access shall be limited to authorized personnel with a business need.","The colocation provider shall supply physical entry controls, surveillance, environmental protections, utilities, and monitored secure areas under contract."]),("Equipment Protection",["Company equipment shall be protected against theft, tampering, power instability, heat, fire, and other environmental threats appropriate to the location.","Portable assets used off-premises shall remain under user control or stored in a secure location.","Storage media shall be inventoried when used, protected during transport, and sanitized or destroyed before disposal or reuse."]),("Maintenance and Disposal",["Equipment maintenance shall be performed by authorized parties and records shall be retained for material repairs or datacenter interventions.","Cabling, supporting utilities, and environmental safeguards for the colocation facility shall be managed through supplier controls and reviewed through supplier assurance.","Retired devices and media shall be wiped or physically destroyed using approved methods."])],"related":["PR-02","PR-10","POL-09"]},
])
docs.extend([
    {"id":"PR-06","type":"Procedure","path":"03_Procedures_and_Standards/PR-06-Logging-Monitoring-and-Alert-Management-Procedure.md","title":"Logging, Monitoring and Alert Management Procedure","purpose":"Describe how security logs, alerts, and monitoring outputs are configured, reviewed, escalated, and retained.","scope":"Applies to identity systems, endpoints, Azure, VPN, code repositories, collaboration platforms, and security tools.","sections":[("Procedure Steps",["Enable audit and security logs for in-scope services in accordance with documented logging requirements.","Review alert queues daily on business days and escalate actionable events under the incident process.","Protect log data from unauthorized modification and retain it according to defined evidence and operational needs.","Verify time synchronization across monitored systems."]),("Records",["Logging standard or matrix","Daily alert review evidence","Escalation tickets","Retention configuration screenshots or exports"])],"related":["POL-05","POL-10"]},
    {"id":"PR-07","type":"Procedure","path":"03_Procedures_and_Standards/PR-07-Vulnerability-Patch-and-Configuration-Management-Procedure.md","title":"Vulnerability, Patch and Configuration Management Procedure","purpose":"Provide the workflow for vulnerability detection, prioritization, remediation, exception handling, and configuration baseline review.","scope":"Applies to company-managed endpoints, Azure workloads, network devices, VPN infrastructure, and other supported systems in scope.","sections":[("Procedure Steps",["Collect vulnerability information from vendors, scanners, platform advisories, and threat intelligence feeds.","Prioritize remediation based on exploitability, exposure, and business impact.","Target remediation timeframes are 7 days for critical, 14 days for high, 30 days for medium, and 90 days for low unless approved otherwise.","Review baseline configurations quarterly and after significant changes."]),("Records",["Vulnerability register","Patch status reports","Approved exceptions","Configuration review records"])],"related":["POL-05","POL-06"]},
    {"id":"PR-08","type":"Standard","path":"03_Procedures_and_Standards/PR-08-Secure-Development-Standard.md","title":"Secure Development Standard","purpose":"Set minimum secure development, review, testing, and release requirements for internally developed software.","scope":"Applies to source code, build pipelines, infrastructure as code, scripts, and application releases.","sections":[("Minimum Requirements",["Repositories shall enforce role-based access, branch protection, and peer review before merge to protected branches.","Developers shall use secure coding guidance appropriate to the language and framework in use.","Static analysis, dependency review, and security testing shall be integrated into the development workflow where feasible.","Secrets shall not be stored in source code or pipeline configuration in plaintext."])],"related":["POL-08","PR-09"]},
    {"id":"PR-09","type":"Procedure","path":"03_Procedures_and_Standards/PR-09-Change-Management-Procedure.md","title":"Change Management Procedure","purpose":"Provide the workflow for normal and emergency changes affecting production systems, security tooling, or critical configuration.","scope":"Applies to application releases, infrastructure changes, network changes, administrative configuration changes, and production-impacting supplier changes.","sections":[("Procedure Steps",["Document the objective, systems affected, implementation plan, rollback plan, validation steps, and approvals before implementation.","Verify testing evidence and segregation of duties for high-risk changes wherever practical.","Record emergency changes immediately and complete retrospective review within five business days.","Close the change after validation and capture any lessons learned or follow-up actions."]),("Records",["Approved change requests","Emergency change reviews","Rollback evidence if used","Post-implementation validation"])],"related":["POL-08","POL-06"]},
    {"id":"PR-10","type":"Procedure","path":"03_Procedures_and_Standards/PR-10-Media-Handling-Sanitization-and-Disposal-Procedure.md","title":"Media Handling, Sanitization and Disposal Procedure","purpose":"Describe approved handling, tracking, sanitization, and destruction practices for storage media and retired equipment.","scope":"Applies to laptops, removable media, failed drives, replacement components, and paper records approved for temporary business use.","sections":[("Procedure Steps",["Track removable or retired media through an inventory or disposal log when used.","Use vendor-supported cryptographic erase, overwrite, or physical destruction methods appropriate to the media type.","Require approval before media leaves company custody except for approved destruction or warranty return processes.","Retain disposal evidence for critical devices and all datacenter storage devices."])],"related":["POL-01","POL-04","PR-02"]},
    {"id":"TMP-01","type":"Template","path":"04_Registers_and_Templates/TMP-01-Management-Review-Minutes-Template.md","title":"Management Review Minutes Template","purpose":"Provide a repeatable structure for annual management review evidence.","scope":"Used during formal ISMS management review.","sections":[("Checklist",["Status of actions from previous management reviews","Changes in internal and external issues relevant to the ISMS","Interested party needs and expectations","Risk assessment and treatment status","Security objectives performance","Incident, nonconformity, and corrective action status","Audit results and compliance status","Resource adequacy and opportunities for improvement"])],"related":["GOV-01","GOV-02","GOV-04"]},
    {"id":"TMP-02","type":"Template","path":"04_Registers_and_Templates/TMP-02-Internal-Audit-Checklist-Template.md","title":"Internal Audit Checklist Template","purpose":"Provide a simple evidence template for internal audit planning and results.","scope":"Used for annual or ad hoc ISMS internal audits.","sections":[("Checklist",["Define audit scope, criteria, auditor, and sampled areas","Record conformities, nonconformities, and observations","Track corrective actions, owners, and due dates","Confirm closure evidence"])],"related":["GOV-01","GOV-04"]},
    {"id":"TMP-03","type":"Template","path":"04_Registers_and_Templates/TMP-03-Risk-Register-Template.md","title":"Risk Register Template","purpose":"Provide a consistent structure for capturing risk statements, owners, scores, treatment decisions, and residual risk acceptance.","scope":"Used for all ISMS risk entries.","review":"Quarterly","sections":[("Suggested Fields",["Risk ID, date raised, asset or process, threat, vulnerability, inherent likelihood, inherent impact, inherent score","Existing controls, treatment action, owner, target date, residual likelihood, residual impact, residual score","Acceptance status, approval, review date, related control IDs"])],"related":["GOV-02","GOV-03"]},
])
docs.extend([
    {"id":"POL-05","type":"Policy","path":"02_Policies/POL-05-Operations-Security-Monitoring-and-Vulnerability-Management-Policy.md","title":"Operations Security, Monitoring and Vulnerability Management Policy","purpose":"Define operational security controls for malware defense, logging, monitoring, vulnerability management, endpoint protection, configuration control, and operational procedures.","scope":"Applies to company-managed endpoints, servers, Azure workloads, VPN infrastructure, SaaS administration, security tooling, and other systems supporting the scoped services.","sections":[("Operational Control Requirements",["Documented operating procedures shall exist for backup monitoring, vulnerability handling, endpoint configuration, incident escalation, and change implementation.","Capacity, service performance, and resource utilization shall be monitored to reduce availability risks.","CrowdStrike or equivalent malware protection shall be deployed on company-managed endpoints and supported servers where technically feasible."]),("Logging and Monitoring",["Security-relevant logs shall be enabled for identity, endpoint, network, cloud, and critical application events.","Monitoring alerts shall be reviewed by authorized personnel and escalated according to incident severity.","System clocks shall be synchronized to trusted time sources to support accurate investigation and evidence."]),("Vulnerabilities and Configurations",["Technical vulnerabilities shall be identified, risk-rated, remediated, and tracked to closure within defined target times.","Baseline configurations shall be defined for endpoints, servers, network devices, and SaaS administration settings.","Web filtering, malware defense, and endpoint hardening shall be enforced to reduce exposure to malicious content and unauthorized software."])],"related":["PR-06","PR-07","POL-06","POL-10","POL-11"]},
    {"id":"POL-06","type":"Policy","path":"02_Policies/POL-06-Network-and-Infrastructure-Security-Policy.md","title":"Network and Infrastructure Security Policy","purpose":"Define security expectations for networks, remote connectivity, datacenter infrastructure, Azure hosting, redundancy, and secure service design.","scope":"Applies to Fortigate, Azure networking, colocation network equipment, remote access, segmentation, and network service providers used within the ISMS scope.","sections":[("Network Requirements",["Network security controls shall be designed and maintained for internal, remote access, management, and production traffic paths.","Critical management networks shall be segregated from user and public-facing networks where technically practical.","Remote access shall use approved VPN or zero-trust mechanisms, strong authentication, and logging."]),("Service Protection",["Security requirements for network services shall be documented for Azure, Fortigate, internet connectivity, and the colocation environment.","Redundancy shall be implemented for critical information processing where business continuity objectives require it.","Network changes shall follow the formal change management process and be tested before production implementation."])],"related":["PR-02","PR-07","PR-09","POL-11"]},
    {"id":"POL-07","type":"Policy","path":"02_Policies/POL-07-Cryptography-Privacy-and-Records-Protection-Policy.md","title":"Cryptography, Privacy and Records Protection Policy","purpose":"Define requirements for encryption, key handling, records protection, legal and contractual compliance, privacy, and protection against data leakage.","scope":"Applies to information stored or transmitted in Microsoft 365, Azure, GitLab, endpoint devices, and any controlled repository containing business or employee information.","sections":[("Cryptography",["Encryption shall be used for laptops, mobile app data containers, network sessions carrying sensitive data, and sensitive cloud storage where supported.","Key management responsibilities shall be assigned, and use of vendor-managed key services shall follow documented configuration and access restrictions."]),("Privacy, Records and Legal Obligations",["Employee personal information shall be protected in accordance with applicable privacy obligations and internal need-to-know principles.","Records that provide contractual, legal, financial, personnel, or security evidence shall be protected from unauthorized alteration or deletion.","Intellectual property, licensing, software use rights, and contractual obligations shall be respected and monitored."]),("Data Leakage Prevention",["Approved DLP, sensitivity labeling, sharing restrictions, and endpoint controls shall be used where supported by Microsoft 365 and other platforms.","The organization shall prohibit use of real customer data in non-production environments and prefer synthetic or sanitized information for testing."])],"related":["POL-01","POL-02","POL-08","PR-03"]},
    {"id":"POL-08","type":"Policy","path":"02_Policies/POL-08-Secure-Development-and-Change-Management-Policy.md","title":"Secure Development and Change Management Policy","purpose":"Establish secure development lifecycle requirements, change control, testing expectations, architecture principles, and protection of source code and environments.","scope":"Applies to internally developed software, infrastructure as code, GitLab repositories, development and test environments, release pipelines, and production deployments.","sections":[("Secure Development Requirements",["Security requirements shall be defined for applications, services, APIs, infrastructure components, and significant design changes before implementation.","Secure architecture principles, threat-informed design, secure coding standards, peer review, and security testing shall be integrated into the SDLC.","Access to source code repositories shall be restricted to authorized personnel and monitored."]),("Environment and Test Control",["Development, test, and production environments shall be separated by accounts, permissions, or equivalent technical controls.","Real customer data shall not be used in non-production environments. Test data shall be synthetic or sanitized where needed.","Audit or assessment activities against production systems shall be planned to avoid service disruption."]),("Change Management",["Production changes shall require documented approval, risk consideration, testing evidence, rollback planning, and post-implementation validation.","Emergency changes shall be logged, approved retrospectively, and reviewed for lessons learned."])],"related":["PR-08","PR-09","POL-05","POL-06"]},
    {"id":"POL-09","type":"Policy","path":"02_Policies/POL-09-Supplier-and-Cloud-Security-Policy.md","title":"Supplier and Cloud Security Policy","purpose":"Define security requirements for supplier selection, contracting, oversight, cloud usage, and ongoing assurance.","scope":"Applies to the third-party manufacturer, colocation provider, Azure, Microsoft 365, GitLab, Atlassian, CrowdStrike, Fortigate support arrangements, and any other suppliers that store, process, transmit, or support in-scope information or systems.","sections":[("Supplier Governance",["Suppliers shall be risk-assessed before onboarding and categorized based on the sensitivity and criticality of the service.","Contracts shall address information security expectations, confidentiality, incident notification, right-to-audit or equivalent assurance, business continuity support, and exit requirements.","Changes in supplier services, certifications, security posture, or critical dependencies shall be reviewed and documented."]),("Cloud Security",["Use of Azure and other cloud services shall follow documented ownership, configuration, access, logging, backup, and exit planning requirements.","Shared responsibility boundaries shall be documented for each material cloud or hosted service.","Current supplier certifications may be used as assurance input, but they do not replace internal due diligence."])],"related":["PR-05","GOV-02","POL-11"]},
    {"id":"POL-10","type":"Policy","path":"02_Policies/POL-10-Incident-Response-and-Evidence-Handling-Policy.md","title":"Incident Response and Evidence Handling Policy","purpose":"Define expectations for preparing for, identifying, assessing, responding to, learning from, and preserving evidence for information security incidents.","scope":"Applies to suspected or confirmed security events involving people, endpoints, cloud services, code repositories, the colocation environment, supplier services, and communications platforms.","sections":[("Response Requirements",["An incident response procedure, severity model, escalation matrix, and communication path shall be maintained and tested.","Potential security events shall be assessed promptly to determine whether they are incidents requiring coordinated response.","Incident records shall document timeline, actions taken, impact, containment, eradication, recovery, and closure decisions."]),("Learning and Evidence",["Lessons learned shall be captured after material incidents or exercises and reflected in risk treatment, procedures, or technical controls.","Evidence shall be collected, preserved, and handled in a manner that supports internal investigation and potential legal or contractual use."])],"related":["PR-06","GOV-02","POL-05","POL-09","TMP-01"]},
    {"id":"POL-11","type":"Policy","path":"02_Policies/POL-11-Business-Continuity-Backup-and-Disaster-Recovery-Policy.md","title":"Business Continuity, Backup and Disaster Recovery Policy","purpose":"Define continuity, backup, recovery, and resilience requirements for the remote-first operating model and supporting technology stack.","scope":"Applies to Azure services, Microsoft 365, company-owned datacenter systems, identity services, source code repositories, collaboration platforms, and endpoint recovery requirements.","sections":[("Continuity Objectives",["Critical services shall be assigned recovery objectives. Default objectives are RTO 8 hours and RPO 4 hours for Tier 1 production and identity services, RTO 24 hours and RPO 24 hours for Tier 2 internal business systems, and RTO 72 hours and RPO 48 hours for Tier 3 supporting services unless documented otherwise.","Continuity plans shall consider remote workforce disruption, loss of cloud service availability, colocation outage, cyber incident, and supplier failure."]),("Backup and Recovery",["Backups shall be enabled for critical data and configuration where supported by the platform or implemented through approved tools.","Backup success and failure alerts shall be reviewed routinely, and restoration capability shall be tested at least semi-annually for critical systems.","Redundancy and failover controls shall be implemented where needed to meet defined recovery objectives."]),("Testing and Review",["Business continuity and disaster recovery exercises shall be performed at least annually, including at least one scenario involving loss of a critical hosted service or site dependency.","Findings from exercises or actual disruptions shall result in documented corrective actions and plan updates."])],"related":["PR-04","GOV-02","POL-09","TMP-01"]},
    {"id":"PR-01","type":"Procedure","path":"03_Procedures_and_Standards/PR-01-Joiner-Mover-Leaver-and-Access-Review-Procedure.md","title":"Joiner, Mover, Leaver and Access Review Procedure","purpose":"Provide the operational process for granting, changing, reviewing, and removing user access.","scope":"Applies to all workforce access to Entra, Microsoft 365, Azure, GitLab, Atlassian services, Fortigate VPN, and privileged administration.","sections":[("Procedure Steps",["Receive a manager-approved request defining role, systems, and privilege level.","Provision baseline access through SSO groups or role-based access controls.","Enable MFA and enforce required endpoint compliance before granting access.","Review access quarterly with system owners and immediately when roles change.","Disable access on termination and complete asset return tracking."]),("Records",["Provisioning and deprovisioning tickets","Quarterly access review evidence","Privileged access review sign-off","Termination checklist and asset return confirmation"])],"related":["POL-02","POL-03"]},
    {"id":"PR-02","type":"Procedure","path":"03_Procedures_and_Standards/PR-02-Datacenter-Access-and-Equipment-Handling-Procedure.md","title":"Datacenter Access and Equipment Handling Procedure","purpose":"Define how authorized personnel access the colocation facility and handle company-owned datacenter equipment.","scope":"Applies to all planned or emergency visits to the colocation provider facility and all work performed on company-owned equipment located there.","sections":[("Procedure Steps",["Maintain a current list of authorized datacenter visitors approved by the Head of IT.","Verify colocation provider access requirements, visitor logs, escort rules, and ticket numbers before each visit.","Record work performed, equipment affected, serial numbers, and any cabling or power changes.","Ensure removed drives or components are tracked, sanitized, or destroyed according to disposal requirements."]),("Records",["Authorized visitor list","Datacenter visit records","Maintenance or replacement records","Media sanitization or destruction records"])],"related":["POL-04","POL-06","PR-10"]},
    {"id":"PR-03","type":"Standard","path":"03_Procedures_and_Standards/PR-03-Mobile-BYOD-and-App-Protection-Standard.md","title":"Mobile BYOD and App Protection Standard","purpose":"Define minimum security requirements for personal mobile devices used to access company email, chat, or documents.","scope":"Applies to iOS and Android devices used under BYOD for company-managed apps and data containers.","sections":[("Minimum Requirements",["Access shall be limited to approved managed applications protected by Intune app protection policies.","Copy and paste, save-as, unmanaged app sharing, and local device storage of company data shall be restricted where technically supported.","A device PIN, biometric protection, screen lock, and supported operating system version are required.","The organization may wipe company data from managed applications without affecting personal content."])],"related":["POL-02","POL-03","POL-07"]},
    {"id":"PR-04","type":"Procedure","path":"03_Procedures_and_Standards/PR-04-Backup-Restore-and-Recovery-Test-Procedure.md","title":"Backup Restore and Recovery Test Procedure","purpose":"Describe how backup health is monitored and how restoration capability is tested.","scope":"Applies to critical Azure workloads, configuration backups, Microsoft 365 data protection arrangements, code repositories, and other systems assigned recovery requirements.","sections":[("Procedure Steps",["Review backup job status and failure alerts according to operational runbooks.","Perform restoration tests for Tier 1 systems at least semi-annually and for Tier 2 systems at least annually.","Document test objectives, source data, recovery time achieved, recovery point achieved, and corrective actions."]),("Records",["Backup monitoring logs","Restore test reports","Corrective action tickets"])],"related":["POL-11"]},
    {"id":"PR-05","type":"Procedure","path":"03_Procedures_and_Standards/PR-05-Supplier-Due-Diligence-and-Review-Procedure.md","title":"Supplier Due Diligence and Review Procedure","purpose":"Define how supplier assurance is performed before onboarding and during ongoing use.","scope":"Applies to material technology, manufacturing, hosting, cloud, SaaS, and security service providers.","sections":[("Procedure Steps",["Classify the supplier by service criticality and information access.","Collect assurance artifacts such as ISO 27001 certificates, security questionnaires, contractual commitments, and incident notification terms.","Document shared responsibility boundaries for Azure, colocation, and other managed services.","Perform at least annual supplier reviews for critical suppliers and whenever material service changes occur."]),("Records",["Supplier register","Due diligence notes","Annual supplier review records","Contract security clauses or addenda"])],"related":["POL-09"]},
])
